    Ok(format!("MC {} 数据下载完成", mc_version))
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Test that the version manifest can be fetched and parsed
    #[tokio::test]
    async fn test_fetch_manifest() {
        let url = "https://launchermeta.mojang.com/mc/game/version_manifest_v2.json";
        let resp = reqwest::get(url).await.expect("HTTP request failed");
        assert!(resp.status().is_success(), "HTTP {}", resp.status());

        let manifest: VersionManifest = resp.json().await.expect("Deserialize manifest");
        assert!(!manifest.versions.is_empty(), "No versions in manifest");
        assert!(!manifest.latest.release.is_empty());

        // Verify 1.21 exists
        let v121 = manifest.versions.iter().find(|v| v.id == "1.21");
        assert!(v121.is_some(), "1.21 not found in manifest");
        assert!(!v121.unwrap().url.is_empty(), "version URL is empty");
    }

    /// Test that a version JSON (1.21) can be fetched and decoded
    #[tokio::test]
    async fn test_fetch_version_json() {
        // First get manifest to find the URL
        let manifest: VersionManifest = reqwest::get(
            "https://launchermeta.mojang.com/mc/game/version_manifest_v2.json",
        )
        .await
        .expect("manifest request")
        .json()
        .await
        .expect("manifest parse");

        let entry = manifest.versions.iter().find(|v| v.id == "1.21")
            .expect("1.21 not found");

        // Fetch version JSON
        let vjson: VersionJson = reqwest::get(&entry.url)
            .await
            .expect("version JSON request")
            .json()
            .await
            .expect("version JSON parse");

        assert!(!vjson.downloads.client.url.is_empty(), "client URL empty");
        assert!(vjson.downloads.client.size > 0, "client size is 0");

.expect("1.21 not found");

        // Fetch version JSON
        let vjson: VersionJson = reqwest::get(&entry.url)
            .await
            .expect("version JSON request")
            .json()
            .await
            .expect("version JSON parse");

        assert!(!vjson.downloads.client.url.is_empty(), "client URL empty");
        assert!(vjson.downloads.client.size > 0, "client size is 0");
        assert!(!vjson.asset_index.url.is_empty(), "asset index URL empty");
        assert!(vjson.asset_index.total_size > 0, "total_size is 0");
    }

    /// Test that a snapshot version also works
    #[tokio::test]
    async fn test_fetch_snapshot() {
        let manifest: VersionManifest = reqwest::get(
            "https://launchermeta.mojang.com/mc/game/version_manifest_v2.json",
        )
        .await
        .expect("manifest request")
        .json()
        .await
        .expect("manifest parse");

        // Find a snapshot version
        let snapshot = manifest.versions.iter()
            .find(|v| v.version_type == "snapshot");

        if let Some(entry) = snapshot {
            let vjson: VersionJson = reqwest::get(&entry.url)
                .await
                .expect("snapshot JSON request")
                .json()
                .await
                .expect("snapshot JSON parse");

            assert!(!vjson.downloads.client.url.is_empty());
            assert!(vjson.asset_index.total_size > 0);
        }
        // If no snapshot, just pass (between releases)
    }
}

use mc_launcher_core::auth::offline::OfflineUser;
use mc_launcher_core::launch::offline::{LaunchConfig, OfflineLauncher};
use std::path::PathBuf;
use tauri::Emitter;

fn mm() -> PathBuf {
    let e = std::env::current_exe().unwrap_or_default();
    e.parent().map(|p| p.join(".MMPC")).unwrap_or_else(|| PathBuf::from(".MMPC"))
}
fn wd(id: &str) -> PathBuf { mm().join("workspaces").join(id) }
fn ps(p: &PathBuf) -> &str { p.to_str().unwrap_or("") }

#[tauri::command]
pub async fn launch_game(
    app: tauri::AppHandle,
    workspace_id: String,
    player_name: String,
    java_path: Option<String>,
) -> Result<String, String> {
    let ws = wd(&workspace_id);
    let pk = ws.join("pack.json");
    let c = std::fs::read_to_string(&pk).map_err(|e| format!("read {e}"))?;
    let cfg: serde_json::Value = serde_json::from_str(&c).map_err(|e| format!("parse {e}"))?;
    let cj = ws.join("versions").join("client.jar");
    if !cj.exists() { return Err("no client.jar".into()); }

    // Collect JVM args
    let mut ja: Vec<String> = cfg["jvm_args"].as_array()
        .map(|a| a.iter().filter_map(|v| v.as_str().map(String::from)).collect())
        .unwrap_or_default();
    ja.push(format!("-Xmx{}M", cfg["max_memory_mb"].as_u64().unwrap_or(4096)));
    ja.push(format!("-Xms{}M", cfg["min_memory_mb"].as_u64().unwrap_or(1024)));
    ja.extend([
        "--add-modules", "ALL-MODULAR-PATH",
        "--add-opens", "java.base/java.lang=ALL-UNNAMED",
        "--add-opens", "java.base/java.util=ALL-UNNAMED",
        "--add-opens", "java.base/java.lang.reflect=ALL-UNNAMED",
        "--add-opens", "java.base/java.text=ALL-UNNAMED",
        "--add-opens", "java.desktop/java.awt=ALL-UNNAMED",
    ].map(String::from));

    let jv = java_path.unwrap_or_else(|| "java".into());
    let mc_ver = cfg["mc_version"].as_str().unwrap_or("1.21");
    let mx = cfg["max_memory_mb"].as_u64().unwrap_or(4096);
    let mi = cfg["min_memory_mb"].as_u64().unwrap_or(1024);
    let w = cfg["window_width"].as_u64().unwrap_or(1280) as u32;
    let h = cfg["window_height"].as_u64().unwrap_or(720) as u32;

    let mut b = LaunchConfig::builder()
        .java_path(&jv).minecraft_jar(ps(&cj))
        .main_class("net.minecraft.client.main.Main")
        .game_dir(ps(&ws)).assets_dir(ps(&ws.join("versions")))
        .asset_index(mc_ver)
        .max_mem(&format!("{mx}M")).min_mem(&format!("{mi}M"))
        .resolution(w, h);
    for a in &ja { b = b.add_jvm_arg(a); }
    let lc = b.build();

    let u = OfflineUser::new(&player_name);
    let mut cmd = OfflineLauncher.build_command(&lc, &u);

let mut b = LaunchConfig::builder()
        .java_path(&jv).minecraft_jar(ps(&cj))
        .main_class("net.minecraft.client.main.Main")
        .game_dir(ps(&ws)).assets_dir(ps(&ws.join("versions")))
        .asset_index(mc_ver)
        .max_mem(&format!("{mx}M")).min_mem(&format!("{mi}M"))
        .resolution(w, h);
    for a in &ja { b = b.add_jvm_arg(a); }
    let lc = b.build();

    let u = OfflineUser::new(&player_name);
    let mut cmd = OfflineLauncher.build_command(&lc, &u);

    // Log command
    let cds: String = std::iter::once(cmd.get_program().to_string_lossy().to_string())
        .chain(cmd.get_args().map(|a| a.to_string_lossy().to_string()))
        .collect::<Vec<_>>().join(" ");
    app.emit("game-status", serde_json::json!({"state":"log","message":cds})).ok();

    cmd.stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped());

    let mut ch = cmd.spawn().map_err(|e| format!("spawn {e}"))?;
    let pid = ch.id();
    let a2 = app.clone();
    std::thread::spawn(move || {
        use std::io::Read;
        if let Some(mut se) = ch.stderr.take() {
            let mut bf = [0u8; 4096];
            while let Ok(n) = se.read(&mut bf) {
                if n == 0 { break; }
                let t = String::from_utf8_lossy(&bf[..n]).to_string();
                a2.emit("game-status", serde_json::json!({"state":"stderr","message":t})).ok();
            }
        }
        let _ = ch.wait();
        a2.emit("game-status", serde_json::json!({"state":"stopped"})).ok();
    });
    Ok(format!("PID: {pid}"))
}

