//! `mc_launcher_core` — Minecraft Launcher SDK
//!
//! A modular SDK for launching Minecraft instances, starting with
//! offline authentication and offline game launch support.
//!
//! # Quick start — offline launch
//!
//! ```rust,no_run
//! use mc_launcher_core::auth::offline::OfflineUser;
//! use mc_launcher_core::launch::offline::{LaunchConfig, OfflineLauncher};
//!
//! let user = OfflineUser::new("Steve");
//! let config = LaunchConfig::builder()
//!     .java_path("/usr/bin/java")
//!     .minecraft_jar("/path/to/1.21/client.jar")
//!     .game_dir("/path/to/game")
//!     .assets_dir("/path/to/assets")
//!     .asset_index("1.21")
//!     .max_mem("4G")
//!     .build();
//!
//! let launcher = OfflineLauncher;
//! let cmd = launcher.build_command(&config, &user);
//! // cmd.spawn() etc.
//! ```

pub mod auth;
pub mod launch;

//! Launch module — Minecraft game process management
//!
//! Builds the Java command-line invocation from a [`LaunchConfig`].
//! Supports offline launch; online / Forge / Fabric variants can be
//! added via the [`Launcher`] trait.

pub mod offline;

use std::process::Command;

/// Common trait for launcher implementations
pub trait Launcher {
    type Config;
    fn build_command(&self, config: &Self::Config) -> Command;
}

/// Errors that can occur during launch preparation
#[derive(Debug, thiserror::Error)]
pub enum LaunchError {
    #[error("Java executable not found: {0}")]
    JavaNotFound(String),

    #[error("Minecraft JAR not found: {0}")]
    MinecraftJarNotFound(String),

    #[error("Library not found: {0}")]
    LibraryNotFound(String),

    #[error("Assets directory not found: {0}")]
    AssetsNotFound(String),

    #[error("Asset index not found: {0}")]
    AssetIndexNotFound(String),

    #[error("Invalid configuration: {0}")]
    InvalidConfig(String),
}

//! Offline Minecraft launcher — builds a Java `Command` for offline play
//!
//! # Example
//! ```no_run
//! use mc_launcher_core::launch::offline::{LaunchConfig, OfflineLauncher};
//! use mc_launcher_core::auth::offline::OfflineUser;
//!
//! let user = OfflineUser::new("Steve");
//! let config = LaunchConfig::builder()
//!     .java_path("/usr/bin/java")
//!     .minecraft_jar("/home/user/.minecraft/versions/1.21/1.21.jar")
//!     .main_class("net.minecraft.client.main.Main")
//!     .game_dir("/home/user/.minecraft")
//!     .assets_dir("/home/user/.minecraft/assets")
//!     .asset_index("1.21")
//!     .max_mem("2G")
//!     .build();
//!
//! let launcher = OfflineLauncher;
//! let cmd = launcher.build_command(&config, &user);
//! ```

